// Function — Get Chat History from Lead (Odoo → limpio, sin mensajes "system", con lead_id)
// Entrada: items con registros de mail.message de Odoo (cada uno tiene model/res_id/body/preview/...)
// Salida: [{ json: { history:[{role,text,ts}], lead_id:Number|null, ...(event?) } }]

const items = $input.all();

// 1) Intenta recuperar {event} si ya venía mergeado
let event = null;
for (const it of items) {
  if (it.json && it.json.event) { event = it.json.event; break; }
}

// Helpers
function cleanHtmlKeepStrong(s){
  return String(s || "")
    .replace(/<br\s*\/?>/gi, "\n")
    .replace(/<\/?(?!strong\b)\w+[^>]*>/g, "") // deja <strong>, quita el resto
    .replace(/\s+/g, " ")
    .trim();
}

function stripPrefixes(text, role){
  let t = String(text || "").trim();
  if (role === "user") {
    t = t.replace(/^<strong>\s*cliente:\s*<\/strong>\s*/i, "")
         .replace(/^cliente:\s*/i, "");
  } else if (role === "assistant") {
    t = t.replace(/^<strong>\s*⋆˚🧚‍♀️?\s*leraysi:?\s*<\/strong>\s*/i, "")
         .replace(/^⋆˚🧚‍♀️?\s*leraysi:?\s*/i, "")
         .replace(/^<strong>\s*leraysi\s*⋆˚🧚‍♀️?:?\s*<\/strong>\s*/i, "")
         .replace(/^leraysi\s*⋆˚🧚‍♀️?:?\s*/i, "");
  }
  return t.trim();
}

function inferRole(mm){
  const messageType = String(mm.message_type || "").toLowerCase();
  const isInternal  = Boolean(mm.is_internal);
  const preview = String(mm.preview || "");
  const body = String(mm.body || "");
  if (messageType === "notification" || isInternal) return "system";
  if (/^<\s*strong>\s*cliente\s*:\s*<\/\s*strong>/i.test(body) || /^cliente\s*:/i.test(preview)) return "user";
  if (/leraysi/i.test(body+preview) || /🧚‍♀️/.test(body+preview) || /⋆˚/.test(body+preview)) return "assistant";
  if (messageType === "comment") return "assistant";
  return "assistant";
}

function toIso(d){
  try { return new Date(d).toISOString(); } catch { return new Date().toISOString(); }
}

function minuteBucket(iso){
  const d = new Date(iso);
  return isNaN(d) ? "0" : `${d.getUTCFullYear()}-${d.getUTCMonth()}-${d.getUTCDate()}-${d.getUTCHours()}-${d.getUTCMinutes()}`;
}

// 2) Mapear Odoo → history crudo (con id para dedupe) y recolectar posibles lead_ids (res_id)
//    Filtra AQUÍ los 'system' para que no entren al historial.
const candidateLeadIds = [];
let raw = items.map(it => {
  const mm = it.json || {};
  if (mm && mm.model === 'crm.lead' && mm.res_id != null) {
    const n = Number(mm.res_id);
    if (Number.isFinite(n)) candidateLeadIds.push(n);
  }
  const role = inferRole(mm);
  const textHtml = cleanHtmlKeepStrong(mm.body || mm.preview || "");
  const text = stripPrefixes(textHtml, role);
  const ts = toIso(mm.date || mm.create_date || new Date().toISOString());
  return { role, text, ts, _id: mm.id || null };
})
.filter(h => h.text && h.role !== "system"); // <— elimina system aquí

// 3) Deducción robusta de lead_id
let lead_id = null;
if (candidateLeadIds.length) {
  const freq = new Map();
  for (const id of candidateLeadIds) freq.set(id, (freq.get(id) || 0) + 1);
  lead_id = [...freq.entries()].sort((a,b) => b[1]-a[1])[0][0];
} else if (event && event.lead_id != null) {
  const ev = Number(event.lead_id);
  lead_id = Number.isFinite(ev) ? ev : null;
}

// 4) Si no hay nada, usa el mensaje actual del evento (si existe)
if (raw.length === 0 && event) {
  const lastText = event?.message?.clean_text || event?.message?.text || "";
  if (lastText.trim()) {
    raw.push({ role: "user", text: lastText.trim(), ts: event.ts_utc || new Date().toISOString() });
  }
}

// 5) Deduplicar (prioridad por id; si no hay id, usa hash por (role+text+minuto))
const seen = new Set();
const out = [];
for (const h of raw) {
  const key = h._id ? `id:${h._id}` : `h:${h.role}:${h.text}:${minuteBucket(h.ts)}`;
  if (seen.has(key)) continue;
  seen.add(key);
  out.push(h);
}

// 6) Ordenar, filtrar system (doble seguro) y recortar
const onlyHuman = out.filter(h => h.role !== "system");
onlyHuman.sort((a,b) => Date.parse(a.ts) - Date.parse(b.ts));
const history = onlyHuman.slice(-200).map(h => ({ role: h.role, text: h.text, ts: h.ts }));

// 7) Salida: history + lead_id (+ event si venía)
const payload = event ? { event, history, lead_id } : { history, lead_id };
return [{ json: payload }];

const input = $input.first().json;

const output = input.output || '';
const leadId = $('UpdateLeadWithLead_Id').first().json.lead_id || 0;

// HTML para Odoo
const htmlBody = `<p><strong>Leraysi⋆˚🧚‍♀️:</strong><br>${output.replace(/\n/g, '<br>')}</p>`;

// Texto plano para WhatsApp
let plainText = output.replace(/\\n/g, '\n');
plainText = plainText.replace(/\*\*(.*?)\*\*/g, '*$1*');
plainText = plainText.replace(/\n\* /g, '\n• ');
plainText = plainText.trim();
plainText = `⋆˚🧚‍♀️Leraysi:\n${plainText}`;

return [
  {
    json: {
      body_html: htmlBody,
      content_whatsapp: plainText,
      lead_id: leadId
    }
  }
];

// Build Lead Row — mapea CLO → fila Baserow (create/update-safe)
// Tabla: LeadsLeraysi
// Entrada esperada: { profile_base:{...}, event:{...} } (desde Normalize Inbound)
// Salida: { keys, row_on_create, row_always, row_upsert }
function toLocalIso(isoUtc, tzOff){
  if (!isoUtc) return null;
  const d = new Date(isoUtc);
  const sign = tzOff?.startsWith('-') ? -1 : 1;
  const [h,m] = String(tzOff||'-03:00').slice(1).split(':').map(Number);
  const offMin = sign * (h*60 + m);
  return new Date(d.getTime() + offMin*60000).toISOString().replace('Z', tzOff||'-03:00');
}
const out = [];
for (const it of items) {
  const pb = it.json.profile_base || {};
  const ev = it.json.event || {};
  const country   = pb.country || 'Desconocido';
  const tz        = pb.tz || '-03:00';
  const channel   = pb.channel || 'whatsapp';
  const nickName  = pb.nick_name || '';
  const fullName  = pb.full_name ?? "";
  const phone     = pb.phone_e164 || '';
  const email     = pb.email ?? "";
  const chatwootId       = pb.chatwoot_id ?? null;
  const chatwootInboxId  = pb.chatwoot_inbox_id ?? null;
  const conversationId   = pb.conversation_id ?? null;
  const msgId      = ev.message_id ?? null;
  const msgText    = String(ev.message_text || '').trim();
  const msgIsoUtc  = ev.msg_created_iso || null;
  const nowIsoUtc  = ev.now_iso_utc || new Date().toISOString();
  // Locales (para first_interaction en create)
  const msgIsoLocal = msgIsoUtc ? toLocalIso(msgIsoUtc, tz) : null;
  // Claves para upsert
  const keys = {
    chatwoot_id: chatwootId,
    phone_number: phone
  };
  // Campos que se setean SOLO en create
  const row_on_create = {
    chatwoot_id: chatwootId,
    chatwoot_inbox_id: chatwootInboxId,
    conversation_id: conversationId,
    nick_name: nickName,
    full_name: fullName,
    phone_number: phone,
    email: email,
    country: country,
    tz: tz,
    channel: channel,
    first_interaction: msgIsoLocal,
    first_interaction_utc: msgIsoUtc,
    last_message: msgText,
    last_message_id: msgId,
    last_activity_iso: nowIsoUtc,
    // Estado conversacional (defaults)
    stage: 'explore',
    priority: 'normal',
    servicio_interes: '',
    interests: [],
    // Flags del salón
    foto_recibida: false,
    presupuesto_dado: false,
    turno_agendado: false,
    turno_fecha: null,
    sena_pagada: false,
    waiting_image: false,
    // Contadores
    services_seen: 0,
    prices_asked: 0,
    deep_interest: 0,
    // Cooldowns
    email_ask_ts: null,
    fullname_ask_ts: null,
    // CRM
    lead_id: 0
  };
  // Campos seguros para actualizar SIEMPRE (update)
  const row_always = {
    channel: channel,
    last_message: msgText,
    last_message_id: msgId,
    last_activity_iso: nowIsoUtc
  };
  // Paquete para upsert
  const row_upsert = { ...row_on_create, ...row_always };
  out.push({ json: { keys, row_on_create, row_always, row_upsert } });
}
return out;

// PickLeadRow — robusto para "empty item" de n8n y para {results:[]}
const items = $input.all().map(i => i.json || {});

// Si viene en formato { results: [...] } lo aplanamos; si no, tomamos los items tal cual
let rows;
if (items.length === 1 && Array.isArray(items[0].results)) {
  rows = items[0].results;
} else {
  rows = items;
}

// Filtramos solo filas "reales": objeto no vacío con algún identificador
const real = rows.filter(r =>
  r && typeof r === 'object' &&
  (r.id != null || r.row_id != null || r.record_id != null) &&
  Object.keys(r).length > 0
);

const hit = real[0] || null;

return [{
  json: {
    exists: !!hit,
    row_id: hit ? (hit.id ?? hit.row_id ?? hit.record_id) : null,
    row: hit || null,
    count: real.length
  }
}];

// CreatePayload — aplana row_upsert/row_on_create y normaliza selects
// Tabla: LeadsLeraysi

const src = $json.row_upsert || $json.row_on_create || {};
const out = Object.fromEntries(
  Object.entries(src).filter(([k, v]) => v !== undefined && v !== null)
);

// ---------- SINGLE SELECTS ----------
const stageAllowed = new Set(['explore', 'consulta', 'presupuesto', 'turno_pendiente', 'turno_confirmado']);
if (out.stage != null) {
  const s = String(out.stage).trim();
  if (!stageAllowed.has(s)) delete out.stage;
}

const priorityAllowed = new Set(['normal', 'high', 'low']);
if (out.priority != null) {
  const p = String(out.priority).trim();
  if (!priorityAllowed.has(p)) delete out.priority;
}

// ---------- MULTI SELECT (interests) ----------
// Categorías de servicios: Corte, Alisado, Color, Uñas, Depilación
if (Array.isArray(out.interests)) {
  out.interests = [...new Set(out.interests.map(v => String(v).trim()))];
} else if (typeof out.interests === 'string') {
  const t = out.interests.trim();
  if (t.startsWith('[')) {
    try { out.interests = JSON.parse(t); } catch { out.interests = []; }
  } else if (t === '') {
    out.interests = [];
  } else {
    out.interests = t.split(',').map(s => s.trim()).filter(Boolean);
  }
}

// ---------- LIMPIEZAS ----------
if (out.email === '') delete out.email;
if (out.full_name === '') delete out.full_name;
if (out.servicio_interes === '') delete out.servicio_interes;
if (out.lead_id === 0) delete out.lead_id;

return [{ json: out }];

// UpdatePayload — usa row_id + row_always al root (sin nulos)
const out = Object.fromEntries(
  Object.entries($json.row_always || {}).filter(([k,v]) => v !== null && v !== undefined)
);
return [{ json: { row_id: $json.row_id, ...out } }];

// CreatePayloadOdoo — a partir del row de Baserow construye el payload limpio para Odoo
// Tabla: LeadsLeraysi

const src = $json;

// Helpers
const sel = (v) => (v && typeof v === 'object' && 'value' in v) ? String(v.value || '').trim()
           : (v == null ? '' : String(v).trim());
const onlyDigits = (s) => String(s || '').replace(/[^\d]/g, '');

// Campos base
const nickName   = src.nick_name || '';
const fullName   = src.full_name || '';
const displayName = fullName || nickName || '';  // Prioriza full_name si existe
const phoneE164  = src.phone_number || src.phone || '';
const email      = (src.email || '').trim();
const country    = sel(src.country);
const channel    = sel(src.channel);
const chatId     = src.chatwoot_id ?? src.keys?.chatwoot_id ?? null;
const inboxId    = src.chatwoot_inbox_id ?? null;
const convId     = src.conversation_id ?? null;
const tz         = src.tz || '-03:00';
const lastMsg    = (src.last_message || '').slice(0, 180);

// === MAPEO ODOO (ajusta IDs a tu instancia) ===
const ODOO = {
  Argentina: {
    country_id: 10,
    state_id_by_area: { '11': 553 },
    default_state_id: 553,
    default_city: 'Buenos Aires'
  },
};

// Resolver country/state/city
let country_id = ODOO[country]?.country_id ?? null;
let state_id   = null;
let city       = '';

if (country === 'Argentina') {
  let d = onlyDigits(phoneE164);
  if (d.startsWith('549')) d = d.slice(3);
  else if (d.startsWith('54')) d = d.slice(2);
  const area = d.slice(0, 2);
  if (ODOO.Argentina.state_id_by_area[area]) {
    state_id = ODOO.Argentina.state_id_by_area[area];
    city = 'Buenos Aires';
  } else {
    state_id = ODOO.Argentina.default_state_id || null;
    city = ODOO.Argentina.default_city || '';
  }
}

// Descripción rica
const parts = [];
if (channel) parts.push(`Canal: ${channel}`);
if (chatId != null) parts.push(`Chatwoot: ${chatId}`);
if (inboxId != null) parts.push(`Inbox: ${inboxId}`);
if (convId != null) parts.push(`Conv: ${convId}`);
if (tz) parts.push(`TZ: ${tz}`);
if (lastMsg) parts.push(`Último: ${lastMsg}`);
const description = parts.join(' • ');

// Construir vals para crm.lead.create
const vals = {
  type: 'lead',
  name: displayName || `Nueva clienta ${channel || ''}`.trim(),
  contact_name: displayName || null,
  phone: phoneE164 || null,
  email_from: email || '',
  description: description || undefined,
  city: city || undefined,
  zip: src.zip || undefined,
  street: src.street || undefined,
};

// Solo añadimos IDs si existen
if (country_id) vals.country_id = country_id;
if (state_id)   vals.state_id   = state_id;

// Salida
return [{
  json: {
    odoo_payload: vals,
    baserow_row_id: src.id ?? src.row_id ?? null,
    debug_country: country
  }
}];

// ============================================================================
// COMPOSE PROFILE - Transforma row de Baserow a objeto profile
// ============================================================================
// Tabla: LeadsLeraysi
// Recibe: Row de Baserow (results[0] o row directo)
// Output: { profile: {...} }
// ============================================================================

const inJson = $json;

// Intenta detectar una "row"
let row = null;
if (Array.isArray(inJson?.results) && inJson.results[0]?.id) {
  row = inJson.results[0];
} else if (Array.isArray(inJson) && inJson[0]?.id) {
  row = inJson[0];
} else if (inJson?.id) {
  row = inJson;
} else if (inJson?.row) {
  row = inJson.row;
}
row = row || {};

const pickVal = (x) => (x && typeof x === 'object' && 'value' in x) ? x.value : (x ?? null);
const toNum   = (x) => {
  if (x === null || x === undefined || x === '') return null;
  const n = Number(x);
  return Number.isFinite(n) ? n : null;
};
const toInt0  = (x) => Number.isFinite(Number(x)) ? Number(x) : 0;

/**
 * Parsea image_analysis de forma segura (puede venir como string o objeto)
 */
function parseImageAnalysis(data) {
  if (!data) return null;
  if (typeof data === 'object') return data;
  if (typeof data === 'string') {
    try {
      return JSON.parse(data);
    } catch (e) {
      return null;
    }
  }
  return null;
}

// Construir description para Odoo
const channel = pickVal(row.channel);
const chatwootId = toNum(row.chatwoot_id);
const inboxId = toNum(row.chatwoot_inbox_id);
const convId = toNum(row.conversation_id);
const tz = row.tz || "-03:00";
const lastMsg = (row.last_message || '').slice(0, 180);

const parts = [];
if (channel) parts.push(`Canal: ${channel}`);
if (chatwootId != null) parts.push(`Chatwoot: ${chatwootId}`);
if (inboxId != null) parts.push(`Inbox: ${inboxId}`);
if (convId != null) parts.push(`Conv: ${convId}`);
if (tz) parts.push(`TZ: ${tz}`);
if (lastMsg) parts.push(`Último: ${lastMsg}`);
const description = parts.join(' • ');

const profile = {
  row_id: row.id ?? null,

  // Identidad / contacto
  nick_name: row.nick_name || null,
  full_name: row.full_name || null,
  phone: row.phone_number || null,
  email: row.email || null,

  // Contexto
  channel: channel,
  country: pickVal(row.country),
  tz: tz,
  stage: pickVal(row.stage) || "explore",
  priority: pickVal(row.priority) || "normal",

  // Servicio de interés
  servicio_interes: row.servicio_interes || null,
  interests: Array.isArray(row.interests) ? row.interests.map(pickVal).filter(Boolean) : [],

  // Flags del salón
  foto_recibida: !!row.foto_recibida,
  presupuesto_dado: !!row.presupuesto_dado,
  turno_agendado: !!row.turno_agendado,
  turno_fecha: row.turno_fecha || null,
  sena_pagada: !!row.sena_pagada,
  waiting_image: !!row.waiting_image,

  // Contadores
  services_seen: toInt0(row.services_seen),
  prices_asked: toInt0(row.prices_asked),
  deep_interest: toInt0(row.deep_interest),

  // IDs y últimos eventos
  lead_id: toNum(row.lead_id),
  chatwoot_id: chatwootId,
  chatwoot_inbox_id: inboxId,
  conversation_id: convId,
  last_message: row.last_message || null,
  last_message_id: row.last_message_id || null,
  last_activity_iso: row.last_activity_iso || null,

  // Cooldowns
  email_ask_ts: row.email_ask_ts || null,
  fullname_ask_ts: row.fullname_ask_ts || null,

  // Image Analysis (nuevo)
  image_analysis: parseImageAnalysis(row.image_analysis),

  // Para Odoo
  description: description,
};

return [{ json: { profile } }];

// ============================================================================
// OUTPUT MAIN LERAYSI v3.2 - Simplificado (pagos van a TurnosLeraysi, no aquí)
// ============================================================================
// Recibe: LLM output (content_whatsapp + state_patch) + state original
// Output: Mensaje para Chatwoot + Update para Baserow
// ============================================================================

console.log("[OutputMain v3.2] Starting...");

// ============================================================================
// 1. OBTENER STATE ORIGINAL (desde Input Main, pasado por el workflow)
// ============================================================================

const inputMainData = $("Input Main").first().json;
const originalState = inputMainData.state;
const protectedFields = inputMainData._protected || [
  "row_id",
  "lead_id",
  "chatwoot_id",
  "chatwoot_inbox_id",
  "conversation_id",
];

if (!originalState) {
  throw new Error("[OutputMain] Missing original state from Input Main");
}

console.log("[OutputMain v3.2] Original state loaded, row_id:", originalState.row_id);

// ============================================================================
// 2. PARSING DEL OUTPUT DEL LLM (ROBUSTO)
// ============================================================================

const llmData = $input.first().json;
let llmOutput;

function cleanJsonString(str) {
  return str
    .replace(/^```json\s*/i, "")
    .replace(/^```\s*/, "")
    .replace(/\s*```$/m, "")
    .replace(/:\s*\n\s*/g, ": ")
    .replace(/,\s*\n\s*"/g, ', "')
    .replace(/"\s*\n\s*}/g, '"}')
    .replace(/"\s*\n\s*,/g, '",')
    .replace(/true\s*\n\s*,/g, "true,")
    .replace(/false\s*\n\s*,/g, "false,")
    .replace(/null\s*\n\s*,/g, "null,")
    .replace(/}\s*\n\s*,/g, "},")
    .replace(/]\s*\n\s*,/g, "],")
    .replace(/[\x00-\x1F\x7F]/g, (char) => {
      if (char === "\n" || char === "\r" || char === "\t") return " ";
      return "";
    })
    .replace(/\s+/g, " ")
    .replace(/,\s*}/g, "}")
    .replace(/,\s*]/g, "]")
    .trim();
}

function extractJson(text) {
  // Intento 1: Parsear directo
  try {
    return JSON.parse(text);
  } catch (e) {
    console.log("[OutputMain v3.2] Parse intento 1 falló");
  }

  // Intento 2: Limpiar y parsear
  const cleaned = cleanJsonString(text);
  try {
    return JSON.parse(cleaned);
  } catch (e) {
    console.log("[OutputMain v3.2] Parse intento 2 falló");
  }

  // Intento 3: Extraer primer JSON completo (bracket-counting)
  const startIdx = text.indexOf('{');
  if (startIdx !== -1) {
    let depth = 0;
    let inString = false;
    let escape = false;
    let endIdx = -1;
    for (let i = startIdx; i < text.length; i++) {
      const ch = text[i];
      if (escape) { escape = false; continue; }
      if (ch === '\\' && inString) { escape = true; continue; }
      if (ch === '"' && !escape) { inString = !inString; continue; }
      if (inString) continue;
      if (ch === '{') depth++;
      if (ch === '}') { depth--; if (depth === 0) { endIdx = i; break; } }
    }
    if (endIdx !== -1) {
      const extracted = text.substring(startIdx, endIdx + 1);
      const matched = cleanJsonString(extracted);
      try {
        return JSON.parse(matched);
      } catch (e) {
        console.log("[OutputMain v3.2] Parse intento 3 falló");
      }
    }
  }

  throw new Error("No se pudo parsear el JSON después de múltiples intentos");
}

if (llmData.output) {
  llmOutput = extractJson(llmData.output);
  console.log("[OutputMain v3.2] ✅ LLM JSON parsed");
} else {
  llmOutput = llmData;
}

// ============================================================================
// 3. EXTRAER content_whatsapp Y state_patch
// ============================================================================

let contentWhatsapp = llmOutput.content_whatsapp || "";
let statePatch = llmOutput.state_patch || {};

// ── RECOVERY: LLM omitió wrapper {"content_whatsapp": "..."} ──
// Caso típico: el LLM escribió el texto directo con state_patch pegado al final
// Raw luce así: "texto...💕", "state_patch": {"stage": "presupuesto"}}
if (!contentWhatsapp && llmData.output) {
  console.log("[OutputMain v3.2] ⚠️ Recovery: content_whatsapp faltante, reconstruyendo...");
  const raw = String(llmData.output);
  const spMarker = '"state_patch"';
  const spIdx = raw.lastIndexOf(spMarker);

  if (spIdx > 0) {
    // Todo antes de "state_patch" es el contenido del mensaje
    let recovered = raw.substring(0, spIdx)
      .replace(/[",\s]+$/, '')  // Limpiar separadores JSON residuales: ",
      .replace(/\\n/g, '\n')    // \n literal → newline real
      .trim();

    if (recovered) {
      contentWhatsapp = recovered;

      // Si extractJson devolvió el objeto state_patch como raíz (sin wrapper),
      // usarlo directamente como statePatch
      if (Object.keys(statePatch).length === 0 && Object.keys(llmOutput).length > 0) {
        statePatch = llmOutput;
      }

      console.log("[OutputMain v3.2] ✅ Recovery exitoso, content length:", recovered.length);
    }
  } else if (raw.trim()) {
    // No hay state_patch en el texto → usar todo como contenido
    contentWhatsapp = raw.replace(/\\n/g, '\n').trim();
    console.log("[OutputMain v3.2] 🔧 Recovery: usando raw output completo como content");
  }
}

if (!contentWhatsapp) {
  throw new Error("[OutputMain] Missing content_whatsapp from LLM");
}

console.log("[OutputMain v3.2] state_patch keys:", Object.keys(statePatch));

// ============================================================================
// 4. APLICAR PATCH AL STATE (protegiendo campos)
// ============================================================================

// ── Validación de stage: corregir valores inválidos del LLM ──
// Baserow `stage` es Single Select con 5 opciones fijas.
// El LLM a veces confunde el flag booleano `turno_agendado` con un valor de stage.
const STAGES_VALIDOS = ['explore', 'consulta', 'presupuesto', 'turno_pendiente', 'turno_confirmado'];
if (statePatch.stage && !STAGES_VALIDOS.includes(statePatch.stage)) {
  const stageOriginal = statePatch.stage;
  if (statePatch.stage === 'turno_agendado') {
    statePatch.stage = 'turno_pendiente';
  } else {
    delete statePatch.stage;
  }
  console.log(`[OutputMain v3.2] 🛡️ Stage inválido "${stageOriginal}" → ${statePatch.stage || '(eliminado)'}`);
}

const mergedState = { ...originalState };

// ── Protección: turno confirmado + pagado → no degradar stage ──
// Cuando el turno ya está agendado y la seña pagada, el stage no puede
// retroceder de "turno_confirmado" a etapas anteriores.
// Esto protege contra el LLM enviando state_patch incorrecto durante
// consultas de disponibilidad para reprogramación.
const turnoConfirmadoPagado = originalState.turno_agendado === true && originalState.sena_pagada === true;
if (turnoConfirmadoPagado && statePatch.stage && statePatch.stage !== "turno_confirmado") {
  console.log(`[OutputMain v3.2] 🛡️ Protección turno confirmado+pagado: bloqueando stage "${statePatch.stage}" → manteniendo "turno_confirmado"`);
  delete statePatch.stage;
}

for (const [key, value] of Object.entries(statePatch)) {
  // Saltar campos protegidos
  if (protectedFields.includes(key)) {
    console.log(`[OutputMain v3.2] ⚠️ Ignorando campo protegido: ${key}`);
    continue;
  }

  // Manejar contadores (incrementales)
  if (["services_seen", "prices_asked", "deep_interest"].includes(key)) {
    const currentVal = Number(mergedState[key]) || 0;
    const patchVal = Number(value) || 0;
    // Si el patch es mayor, usar el patch (asume que LLM incrementó)
    // Si no, mantener el original
    mergedState[key] = Math.max(currentVal, patchVal);
    console.log(`[OutputMain v3.2] Contador ${key}: ${currentVal} → ${mergedState[key]}`);
    continue;
  }

  // Manejar arrays (interests) - merge sin duplicados
  if (key === "interests" && Array.isArray(value)) {
    const currentArr = Array.isArray(mergedState.interests) ? mergedState.interests : [];
    const merged = [...new Set([...currentArr, ...value])];
    mergedState.interests = merged;
    console.log(`[OutputMain v3.2] Interests merged:`, merged);
    continue;
  }

  // Manejar timestamps de solicitud (true → timestamp ISO, false → null)
  if ((key === "email_ask_ts" || key === "fullname_ask_ts") && typeof value === 'boolean') {
    if (value === false) {
      // LLM dice "ya no preguntar" → limpiar el campo (Baserow necesita null, no false)
      mergedState[key] = null;
      console.log(`[OutputMain v3.2] ${key} → null (LLM envió false)`);
      continue;
    }
    // value === true → convertir a timestamp
    // Formato para Baserow: YYYY-MM-DDThh:mm:ss-03:00
    // Ajustar UTC a Argentina (UTC-3)
    const now = new Date();
    const argentinaTime = new Date(now.getTime() - (3 * 60 * 60 * 1000));
    const offset = '-03:00';
    const year = argentinaTime.getUTCFullYear();
    const month = String(argentinaTime.getUTCMonth() + 1).padStart(2, '0');
    const day = String(argentinaTime.getUTCDate()).padStart(2, '0');
    const hours = String(argentinaTime.getUTCHours()).padStart(2, '0');
    const minutes = String(argentinaTime.getUTCMinutes()).padStart(2, '0');
    const seconds = String(argentinaTime.getUTCSeconds()).padStart(2, '0');
    const timestamp = `${year}-${month}-${day}T${hours}:${minutes}:${seconds}${offset}`;
    mergedState[key] = timestamp;
    console.log(`[OutputMain v3.2] ${key} convertido a timestamp:`, timestamp);
    continue;
  }

  // Campos normales: sobrescribir
  mergedState[key] = value;
}

console.log("[OutputMain v3.2] Merged state:");
console.log("  - stage:", mergedState.stage);
console.log("  - servicio_interes:", mergedState.servicio_interes);
console.log("  - waiting_image:", mergedState.waiting_image);

// ============================================================================
// 5. GENERAR NOTES DINÁMICO
// ============================================================================

function generateContextualNote(state) {
  const stage = state.stage;
  const servicio = state.servicio_interes;

  if (stage === "explore") {
    return "Conversación inicial - explorando servicios";
  }

  if (stage === "consulta") {
    if (state.waiting_image) {
      return `Consulta ${servicio} - Esperando foto`;
    }
    return `Consulta sobre ${servicio || "servicios"}`;
  }

  if (stage === "presupuesto") {
    const analysis = state.image_analysis;
    if (analysis) {
      return `Presupuesto ${servicio} - Cabello ${analysis.length || ""} (${analysis.complexity || "media"})`;
    }
    return `Presupuesto dado - ${servicio}`;
  }

  if (stage === "turno_pendiente") {
    return `Gestionando turno - ${servicio}`;
  }

  if (stage === "turno_confirmado") {
    return `Turno confirmado - ${servicio} (${state.turno_fecha || "fecha pendiente"})`;
  }

  return "Conversación en curso";
}

// ============================================================================
// 6. HELPERS
// ============================================================================

function escapeHtml(str) {
  if (!str) return "";
  return String(str)
    .replace(/&/g, "&amp;")
    .replace(/</g, "&lt;")
    .replace(/>/g, "&gt;");
}

function sanitizeText(str, maxLength = 3500) {
  if (!str) return "";
  let text = String(str)
    .replace(/\r\n?/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .trim();
  if (text.length > maxLength) {
    text = text.slice(0, maxLength - 1) + "…";
  }
  return text;
}

// ============================================================================
// 7. CONSTRUIR CONTENIDO HTML
// ============================================================================

const whatsappContent = sanitizeText(contentWhatsapp);
const bodyHtml = `<p>${escapeHtml(whatsappContent)}</p>`;

// ============================================================================
// 8. CONSTRUIR BASEROW UPDATE (estructura unificada)
// ============================================================================

const baserowUpdate = {
  // IDs (para identificar el row)
  row_id: mergedState.row_id,

  // Datos del cliente (actualizables por LLM)
  full_name: mergedState.full_name || null,
  email: mergedState.email || null,

  // Funnel state
  stage: mergedState.stage,
  priority: mergedState.priority || "normal",
  servicio_interes: mergedState.servicio_interes || null,
  interests: Array.isArray(mergedState.interests) ? mergedState.interests : [],

  // Flags del proceso
  foto_recibida: Boolean(mergedState.foto_recibida),
  presupuesto_dado: Boolean(mergedState.presupuesto_dado),
  turno_agendado: Boolean(mergedState.turno_agendado),
  turno_fecha: mergedState.turno_fecha || null,
  sena_pagada: Boolean(mergedState.sena_pagada),
  waiting_image: Boolean(mergedState.waiting_image),

  // NOTA: Campos de pago (link_pago, mp_preference_id, precio, etc.)
  // NO van aquí - se guardan en TurnosLeraysi via sub-workflow

  // Contadores
  services_seen: mergedState.services_seen ?? 0,
  prices_asked: mergedState.prices_asked ?? 0,
  deep_interest: mergedState.deep_interest ?? 0,

  // Cooldowns (Baserow datetime: solo acepta string ISO o null, NUNCA boolean)
  email_ask_ts: typeof mergedState.email_ask_ts === 'string' ? mergedState.email_ask_ts : null,
  fullname_ask_ts: typeof mergedState.fullname_ask_ts === 'string' ? mergedState.fullname_ask_ts : null,

  // Nota dinámica
  notes: generateContextualNote(mergedState),

  // Análisis de imagen (si existe)
  image_analysis: mergedState.image_analysis
    ? JSON.stringify(mergedState.image_analysis)
    : null,
};

console.log("[OutputMain v3.2] Notes generado:", baserowUpdate.notes);

// ============================================================================
// 9. OUTPUT FINAL
// ============================================================================

const output = {
  content_whatsapp: {
    content: whatsappContent,
    message_type: "outgoing",
    content_type: "text",
  },
  body_html: bodyHtml,
  lead_id: mergedState.lead_id,
  row_id: mergedState.row_id,
  baserow_update: baserowUpdate,
  state: mergedState,
  meta: {
    timestamp: new Date().toISOString(),
    version: "leraysi-output@3.1",
    patch_applied: Object.keys(statePatch),
  },
};

console.log("[OutputMain v3.2] ✅ Done");

return [{ json: output }];

// Normalize Inbound — country + tz + channel + timestamps + último mensaje → CLO
// Entrada: ítems con payload Chatwoot (como el que compartiste)
// Salida: { profile_base: {...}, event: {...} }

function pickLatestMessage(messages = []) {
  if (!Array.isArray(messages) || messages.length === 0) return null;

  const toMs = (v) => {
    if (v == null) return -Infinity;
    if (typeof v === 'number') {
      // epoch segundos o ms
      return v < 1e12 ? v * 1000 : v;
    }
    const s = String(v);
    // num como string
    if (/^\d+$/.test(s)) {
      const n = parseInt(s, 10);
      return n < 1e12 ? n * 1000 : n;
    }
    // ISO
    const t = Date.parse(s);
    return Number.isFinite(t) ? t : -Infinity;
  };

  let latest = messages[0];
  let latestMs = toMs(messages[0]?.created_at);

  for (const m of messages.slice(1)) {
    const ms = toMs(m?.created_at);
    if (ms > latestMs) {
      latest = m;
      latestMs = ms;
    }
  }
  return latest;
}

function parseToIso(value) {
  if (value == null) return new Date().toISOString();
  if (typeof value === 'number') {
    const ms = value < 1e12 ? value * 1000 : value;
    return new Date(ms).toISOString();
  }
  const s = String(value);
  if (/^\d+$/.test(s)) {
    const n = parseInt(s, 10);
    const ms = n < 1e12 ? n * 1000 : n;
    return new Date(ms).toISOString();
  }
  const t = Date.parse(s);
  return Number.isFinite(t) ? new Date(t).toISOString() : new Date().toISOString();
}

function normalizeChannel(raw) {
  const s = String(raw || '').toLowerCase();
  const base = s.includes('::') ? s.split('::').pop() : s;
  if (base.includes('whats')) return 'whatsapp';
  if (base.includes('insta')) return 'instagram';
  if (base.includes('face')) return 'facebook';
  if (base.includes('sms')) return 'sms';
  if (base.includes('mail') || base.includes('email')) return 'email';
  if (base.includes('web') || base.includes('site')) return 'web';
  return base || 'unknown';
}

function detectCountryByPhone(phone) {
  const codeMap = {
    '+593': 'Ecuador',
    '+595': 'Paraguay',
    '+591': 'Bolivia',
    '+592': 'Guyana',
    '+594': 'Guayana Francesa',
    '+598': 'Uruguay',
    '+597': 'Surinam',
    '+5989': 'Uruguay', // ejemplo de prefijo más largo si quisieras ajustar
    '+58': 'Venezuela',
    '+57': 'Colombia',
    '+56': 'Chile',
    '+55': 'Brasil',
    '+54': 'Argentina',
    '+52': 'México',
    '+51': 'Perú',
    '+34': 'España',
    '+1': 'Estados Unidos'
  };
  const p = String(phone || '');
  const prefixes = Object.keys(codeMap).sort((a, b) => b.length - a.length); // más largo primero
  const hit = prefixes.find(pref => p.startsWith(pref));
  return codeMap[hit] || 'Desconocido';
}

function tzByCountry(country) {
  const tzMap = {
    'Argentina': '-03:00',
    'España': '+01:00',      // simple, sin DST por ahora
    'México': '-06:00',
    'Colombia': '-05:00',
    'Chile': '-04:00',
    'Perú': '-05:00',
    'Venezuela': '-04:00',
    'Brasil': '-03:00',
    'Paraguay': '-04:00',
    'Ecuador': '-05:00',
    'Bolivia': '-04:00',
    'Estados Unidos': '-05:00',
    'Uruguay': '-03:00',
    'Surinam': '-03:00',
    'Guayana Francesa': '-03:00',
    'Guyana': '-04:00',
    'Desconocido': '-03:00'
  };
  return tzMap[country] || '-03:00';
}

function toLocalIso(isoUtc, tzOff) {
  // Convierte un ISO UTC a ISO con offset y hora local (sumando el offset).
  // Ej: "2025-09-16T14:25:27Z" + "-03:00" → "2025-09-16T11:25:27-03:00"
  const d = new Date(isoUtc);
  const sign = tzOff.startsWith('-') ? -1 : 1;
  const [h, m] = tzOff.slice(1).split(':').map(Number);
  const offMin = sign * (h * 60 + m);
  const localMs = d.getTime() + offMin * 60000;
  const localIso = new Date(localMs).toISOString().replace('Z', tzOff);
  return localIso;
}

function cleanText(s) {
  return String(s || '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/?(?!strong\b)\w+[^>]*>/g, '') // mantiene <strong>, quita el resto
    .replace(/\s+/g, ' ')
    .trim();
}

const out = [];

for (const item of items) {
  const data = item.json || {};
  const body = data.body || {};
  const conv = body.conversation || {};
  const msgs = Array.isArray(conv.messages) ? conv.messages : [];

  // Último mensaje real
  const lastMsg = pickLatestMessage(msgs) || {};
  const msgId = lastMsg.id ?? null;
  const msgText = lastMsg.processed_message_content ?? lastMsg.content ?? body.content ?? '';
  const msgCreatedIso = parseToIso(lastMsg.created_at ?? body.created_at ?? data.created_at);

  // Identidad / IDs
  const sender = lastMsg.sender || conv.meta?.sender || data.sender || {};
  const nickName = sender.name ?? '';
  const phone = sender.phone_number ?? '';
  const email = sender.email ?? null;

  const chatwootId = sender.id ?? conv.meta?.sender?.id ?? data.sender?.id ?? null;
  const chatwootInboxId = conv.contact_inbox?.id ?? null;
  const conversationId = conv.id ?? null;

  // Country & tz
  const country = detectCountryByPhone(phone);
  const tz = tzByCountry(country);

  // Canal normalizado
  const channel = normalizeChannel(conv.channel || data.inbox?.name);

  // Timestamps de evento
  const nowIsoUtc = new Date().toISOString();
  const nowIsoLocal = toLocalIso(nowIsoUtc, tz);

  const profile_base = {
    nick_name: nickName || '',
    phone_e164: phone || '',
    email: email || null,
    country,
    tz,
    channel,
    chatwoot_id: chatwootId,
    chatwoot_inbox_id: chatwootInboxId,
    conversation_id: conversationId
  };

  const event = {
    message_id: msgId,
    message_text: cleanText(msgText),
    msg_created_iso: msgCreatedIso,
    now_iso_utc: nowIsoUtc,
    now_iso_local: nowIsoLocal
  };

  out.push({ json: { profile_base, event } });
}

return out;

// ============================================================================
// INPUT MAIN v3.1 - Con contexto temporal expl\u00edcito
// ============================================================================

const inputData = $input.first().json;
const { history, lead_id, profile } = inputData;
const state = profile;

if (!history || !state) {
  throw new Error("[InputMain] Missing required fields: history or state");
}

// ============================================================================
// 2. CAMPOS PROTEGIDOS (no modificables por LLM)
// ============================================================================
const PROTECTED_FIELDS = ["row_id", "lead_id", "chatwoot_id", "chatwoot_inbox_id", "conversation_id"];

// ============================================================================
// 3. BUILD META + CONTEXTO TEMPORAL
// ============================================================================
const now = new Date();
const diasSemana = ['Domingo', 'Lunes', 'Martes', 'Mi\u00e9rcoles', 'Jueves', 'Viernes', 'S\u00e1bado'];
const meses = ['enero', 'febrero', 'marzo', 'abril', 'mayo', 'junio', 'julio', 'agosto', 'septiembre', 'octubre', 'noviembre', 'diciembre'];
const fechaHumana = `${diasSemana[now.getDay()]} ${now.getDate()} de ${meses[now.getMonth()]} de ${now.getFullYear()}`;

const meta = {
  now_ts: now.toISOString(),
  now_human: fechaHumana,
  history_len: history.length,
  channel: state.channel || "whatsapp",
  country: state.country || "Argentina",
  tz: state.tz || "-03:00",
};

// ============================================================================
// 4. BUILD USER PROMPT
// ============================================================================
const lastUserMessage = history.filter((m) => m.role === "user").slice(-1)[0];
const userMessageText = lastUserMessage?.text || "[Foto enviada]";
const displayName = state.full_name || state.nick_name || "clienta";

// Secci\u00f3n de an\u00e1lisis de imagen (solo si existe)
let imageSection = "";
if (state.image_analysis) {
  const ia = state.image_analysis;
  // Precios base de servicios de cabello (ajustados por largo detectado)
  const PRECIOS_BASE = {
    'Corte mujer': 8000, 'Alisado brasile\u00f1o': 45000, 'Alisado keratina': 55000,
    'Mechas completas': 35000, 'Tintura ra\u00edz': 15000, 'Tintura completa': 25000,
    'Balayage': 50000
  };
  // Precios fijos (no dependen del largo del cabello)
  const PRECIOS_FIJOS = {
    'Manicura simple': 5000, 'Manicura semipermanente': 8000, 'Pedicura': 6000,
    'Depilaci\u00f3n cera piernas': 10000, 'Depilaci\u00f3n cera axilas': 4000,
    'Depilaci\u00f3n cera bikini': 6000, 'Depilaci\u00f3n l\u00e1ser piernas': 25000,
    'Depilaci\u00f3n l\u00e1ser axilas': 12000
  };
  const MULT = { 'corto': 1.0, 'medio': 1.1, 'largo': 1.2 };
  const mult = MULT[ia.length] || 1.0;

  const tablaCabello = Object.entries(PRECIOS_BASE)
    .map(([s, base]) => `- ${s}: $${Math.round(base * mult).toLocaleString('es-AR')}`)
    .join('\n');
  const tablaFijos = Object.entries(PRECIOS_FIJOS)
    .map(([s, p]) => `- ${s}: $${p.toLocaleString('es-AR')}`)
    .join('\n');

  imageSection = `
## Foto Recibida
Largo: ${ia.length} | Textura: ${ia.texture} | Condici\u00f3n: ${ia.condition}
Color: ${ia.current_color} | ${ia.is_dyed ? "Te\u00f1ido" : "Sin te\u00f1ir"} | ${ia.has_roots ? "Con ra\u00edces" : "Sin ra\u00edces"}

## PRECIOS FINALES (ya calculados, usar EXACTAMENTE estos valores)
### Servicios de cabello (ajustados para cabello ${ia.length}):
${tablaCabello}
### Servicios precio fijo:
${tablaFijos}

\u26a0\ufe0f USAR estos precios EXACTOS al dar presupuesto y al llamar tools. NO aplicar ajustes adicionales.
`;
}

// Formatear historial completo (\u00faltimos 10 mensajes)
const recentHistory = history.slice(-10);
const historyFormatted = recentHistory
  .map((m) => `[${m.role.toUpperCase()}]: ${m.text}`)
  .join("\n\n");

const userPrompt = `## Historial de Conversaci\u00f3n
${historyFormatted}

---

## \ud83d\udcc5 Contexto Temporal
**Hoy es: ${fechaHumana}**

## Estado Actual del Lead
- Stage: ${state.stage}
- Servicio de inter\u00e9s: ${state.servicio_interes || "ninguno"}
- Foto recibida: ${state.foto_recibida ? "S\u00cd" : "no"}
- Presupuesto dado: ${state.presupuesto_dado ? "S\u00cd" : "no"}
- Esperando foto: ${state.waiting_image ? "S\u00cd" : "no"}
- Contadores: services_seen=${state.services_seen}, prices_asked=${state.prices_asked}, deep_interest=${state.deep_interest}
- Datos cliente: full_name=${state.full_name || "pendiente"}, email=${state.email || "pendiente"}
${imageSection}
---

## \u00daltimo Mensaje a Responder
"${userMessageText}"

Responde a este mensaje actualizando el state seg\u00fan corresponda.
`;

// ============================================================================
// 5. OUTPUT
// ============================================================================
return [
  {
    json: {
      userPrompt,
      lead_id,
      state,
      meta,
      _protected: PROTECTED_FIELDS,
    },
  },
];

