// Helper functions
function num(x, d=0){ const n = Number(x); return Number.isFinite(n) ? n : d; }
function nul(x){ return (x === '' || x === undefined) ? null : x; }
function val(v){ return (v && typeof v === 'object' && 'value' in v) ? v.value : v; }

// Función robusta para extraer JSON
function extractJSON(text) {
  // Intentar parsear directo
  try {
    return JSON.parse(text);
  } catch (e) {
    // Continuar con limpieza
  }

  // Limpiar markdown ```json ... ```
  let cleaned = text.replace(/```json\s*/gi, '').replace(/```\s*/g, '').trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    // Continuar con más limpieza
  }

  // Buscar JSON entre llaves { ... }
  const jsonMatch = text.match(/\{[\s\S]*\}/);
  if (jsonMatch) {
    try {
      return JSON.parse(jsonMatch[0]);
    } catch (e) {
      // Continuar
    }
  }

  // Último intento: limpiar caracteres problemáticos
  cleaned = text
    .replace(/```json\s*/gi, '')
    .replace(/```\s*/g, '')
    .replace(/^\s*[\r\n]+/, '')
    .replace(/[\r\n]+\s*$/, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (e) {
    // Retornar objeto de error si todo falla
    return {
      is_hair_photo: false,
      error: true,
      notes: "No se pudo parsear la respuesta de Vision: " + e.message,
      raw_response: text.substring(0, 200)
    };
  }
}

